INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('18226885f1a49c09', 'RI', '["federal","state","county"]', 'ballot_access', 'What is the primary election system in Rhode Island?', '["Are Rhode Island primaries open or closed?","Do I have to register with a party to vote in the RI primary?","Can unaffiliated voters participate in the Rhode Island primary?"]', 'Rhode Island utilizes a semi-open primary system. Voters who are officially affiliated with a political party may only vote in that party''s primary. However, unaffiliated voters (independents) are permitted to participate by choosing to affiliate with a party at the polling place on Primary Day to cast that party''s ballot.', 'https://elections.ri.gov/elections/primary-elections', 'Rhode Island Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'All voters and candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('9bc6fa4dd5a7c0d5', 'RI', '["federal","state","county"]', 'runoff_rules', 'Does Rhode Island hold primary runoff elections?', '["What is the threshold to win a primary in RI?","Does Rhode Island require a majority to win a primary?","Rhode Island primary runoff rules"]', 'No. Rhode Island does not hold primary runoff elections. A candidate does not need to secure a 50%+1 majority to win a party''s nomination; the candidate who receives a simple plurality (the most votes) in the primary advances directly to the general election.', 'https://elections.ri.gov/', 'Rhode Island Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'All primary candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('89da6c12c612bfd6', 'RI', '["federal","state","county"]', 'ballot_access', 'Are write-in candidates permitted in Rhode Island?', '["Do write-in votes count in RI?","How to register as a write-in candidate in Rhode Island","Write-in filing deadline Rhode Island"]', 'Yes, and Rhode Island is highly distinctive in this regard: there is absolutely NO declaration requirement or pre-election paperwork required to run as a write-in candidate. Write-in votes cast on the ballot are automatically valid and tabulated by election officials, though candidates are advised to notify their local board of canvassers informally.', 'https://elections.ri.gov/faq', 'Rhode Island Board of Elections - FAQ', '2026-05-17', 'static', 'official_source_direct', 'Write-in candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('3b6cfecccbc695ca', 'RI', '["federal","state","county"]', 'filing_requirements', 'What is the candidate filing deadline for Rhode Island in 2026?', '["When do candidates file for office in Rhode Island?","Rhode Island filing deadline 2026","June filing deadline RI"]', 'Under Rhode Island law, candidates must file their Declaration of Candidacy during a specific three-day window: the last consecutive Monday, Tuesday, and Wednesday in June. For the 2026 cycle, this filing period is June 22 through June 24, 2026, closing at 4:00 p.m. on June 24.', 'https://vote.sos.ri.gov/Forms/Elections/Guides/2026ElecCal.pdf', 'Rhode Island Department of State - 2026 Election Calendar', '2026-05-17', 'per_cycle', 'official_source_direct', 'All candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('575fc3548b5c6bbb', 'RI', '["federal","state"]', 'ballot_access', 'What is the petition signature threshold for independent candidates in Rhode Island?', '["Independent candidate ballot access Rhode Island","Running without a party in RI 2026","How many signatures for independent US Senate RI"]', 'Independent candidates must submit nomination papers signed by registered voters. For statewide offices (like U.S. Senate or Governor), candidates need 1,000 valid signatures. For U.S. House, they need 500 signatures. For State Senate, 100 signatures are required, and for State Representative, 50 signatures.', 'https://vote.sos.ri.gov/', 'Rhode Island Department of State', '2026-05-17', 'static', 'official_source_direct', 'Independent candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('0a4c335782ab3399', 'RI', '["federal","state","county"]', 'ballot_access', 'Does Rhode Island have a sore loser law?', '["Can I run as an independent if I lose the RI primary?","Rhode Island sore loser statute","General election ballot access after primary defeat RI"]', 'Yes. Rhode Island enforces a sore loser law. A candidate who seeks a party''s nomination in a primary election and is defeated cannot subsequently have their name placed on the general election ballot as an independent candidate for the same office.', 'https://ballotpedia.org/Sore_loser_laws_by_state', 'Ballotpedia - Sore Loser Laws', '2026-05-17', 'static', 'secondary_source', 'Major party candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('de0a40dc1323a59a', 'RI', '["state"]', 'ballot_access', 'Do the Governor and Lieutenant Governor run on a joint ticket in Rhode Island?', '["Rhode Island joint ticket rules","How are Lt Gov candidates selected in RI?","Does the Governor pick a running mate in Rhode Island?"]', 'No. In Rhode Island, the Governor and Lieutenant Governor are elected completely separately. They run in distinct primary and general elections and appear as separate items on the ballot, meaning voters can elect a Governor and Lieutenant Governor from two different political parties.', 'https://elections.ri.gov/', 'Rhode Island Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'Statewide executive candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('a6038d1f97e383ec', 'RI', '["federal","state","county"]', 'election_dates', 'When are the primary and general elections in Rhode Island for 2026?', '["Rhode Island primary date 2026","When is Election Day 2026 in Rhode Island?","September primary Rhode Island"]', 'The Rhode Island primary election will be held on Wednesday, September 9, 2026. (State law mandates that if the standard Tuesday primary falls on the day immediately following Labor Day, the primary is shifted to Wednesday). The general election will be held on Tuesday, November 3, 2026. Polls open at 7:00 a.m. and close at 8:00 p.m.', 'https://vote.sos.ri.gov/Forms/Elections/Guides/2026ElecCal.pdf', 'Rhode Island Department of State - 2026 Election Calendar', '2026-05-17', 'per_cycle', 'official_source_direct', 'All candidates and voters', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('e8ce431fc78a0ee0', 'RI', '["state"]', 'election_dates', 'Is Governor Dan McKee running for re-election in 2026?', '["Rhode Island Governor election 2026","Who is defending the RI Governor seat?","Is Dan McKee on the 2026 ballot?"]', 'Yes. Counter to older baseline assumptions, Rhode Island switched to four-year gubernatorial terms in 1994 and elects its Governor entirely on the midterm cycle (e.g., 2022, 2026). Governor Dan McKee (D) won a full term in 2022 and is eligible to defend his seat on the 2026 ballot.', 'https://ballotpedia.org/Governor_of_Rhode_Island', 'Ballotpedia - Governor of Rhode Island', '2026-05-17', 'static', 'secondary_source', 'Gubernatorial candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('7438b82c6b2fd856', 'RI', '["federal"]', 'election_dates', 'Which U.S. Senate seat is up for election in Rhode Island in 2026?', '["Is Jack Reed up for re-election in 2026?","When is Sheldon Whitehouse''s next election?","Rhode Island US Senate cycle 2026"]', 'The Class 2 U.S. Senate seat currently held by Jack Reed (D) is up for election in 2026. Senator Sheldon Whitehouse (Class 1) was re-elected in 2024 and will not appear on the ballot again until 2030.', 'https://www.senate.gov/senators/Class_II.htm', 'U.S. Senate - Class II Senators', '2026-05-17', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('b98bfb126fd04109', 'RI', '["federal"]', 'election_dates', 'How many U.S. House districts are in Rhode Island for the 2026 election?', '["Rhode Island congressional apportionment","Are all RI congressional seats up in 2026?","Number of US Representatives from Rhode Island"]', 'Rhode Island is apportioned 2 U.S. House districts. Both seats are on the 2026 ballot, as U.S. Representatives serve two-year terms.', 'https://elections.ri.gov/', 'Rhode Island Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('86839dc640f3bc25', 'RI', '["state"]', 'election_dates', 'Which Rhode Island State Legislature seats are up for election in 2026?', '["Are all Rhode Island House seats up in 2026?","Rhode Island Senate election cycle 2026","Which legislative districts are on the ballot in RI?"]', 'In Rhode Island, all members of the General Assembly serve two-year terms. Therefore, all 75 seats in the Rhode Island House of Representatives and all 38 seats in the Rhode Island State Senate are on the 2026 ballot.', 'https://en.wikipedia.org/wiki/Rhode_Island_General_Assembly', 'Wikipedia - Rhode Island General Assembly', '2026-05-17', 'per_cycle', 'secondary_source', 'State legislative candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('96f9d77c36096d94', 'RI', '["state"]', 'election_dates', 'Which statewide executive offices are up for election in Rhode Island in 2026?', '["Is the Attorney General up in 2026?","RI statewide election list 2026","When is the Secretary of State election in RI?"]', 'Rhode Island elects all of its major statewide executive officers concurrently on a four-year midterm cycle. In 2026, the offices of Governor, Lieutenant Governor, Secretary of State, Attorney General, and General Treasurer are all on the ballot.', 'https://en.wikipedia.org/wiki/2026_Rhode_Island_elections', 'Wikipedia - 2026 Rhode Island Elections', '2026-05-17', 'per_cycle', 'secondary_source', 'Statewide candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('ce180d9050b3b2db', 'RI', '["judicial"]', 'election_dates', 'How are Rhode Island Supreme Court justices selected and are they on the ballot?', '["Rhode Island judicial elections 2026","Are RI judges elected or appointed?","Supreme Court elections Rhode Island"]', 'Rhode Island does NOT hold judicial elections. Supreme Court justices are nominated by the Governor from a list submitted by the Judicial Nominating Commission and must be confirmed by both chambers of the General Assembly. They hold life tenure and never appear on a public ballot.', 'https://www.courts.ri.gov/Courts/SupremeCourt/Pages/default.aspx', 'Rhode Island Judiciary', '2026-05-17', 'static', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('d5d2697ead0c8e72', 'RI', '["state"]', 'election_dates', 'What is the schedule for the Rhode Island General Assembly sessions?', '["When does the RI legislature meet?","Rhode Island legislative session length","Is the Rhode Island legislature full time?"]', 'The Rhode Island General Assembly is a part-time legislature that meets annually. The regular session formally convenes on the first Tuesday in January of each year and typically runs through late June.', 'https://www.rilegislature.gov/', 'Rhode Island General Assembly', '2026-05-17', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('ba92c2bd85a114b8', 'RI', '["state"]', 'candidate_eligibility', 'What are the eligibility requirements to run for Governor of Rhode Island?', '["Age and residency for Rhode Island Governor","Rhode Island Constitution Governor qualifications","Who is eligible to be Governor of RI?"]', 'Under Article IX of the Rhode Island Constitution, a candidate for Governor must be a qualified elector (registered voter) of the state and must have been a resident of Rhode Island for at least 30 days immediately prior to the election.', 'https://elections.ri.gov/', 'Rhode Island Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'Gubernatorial candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('e81c88a0f7d60fb0', 'RI', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for the Rhode Island State Legislature?', '["Qualifications for RI State Representative","Age requirement Rhode Island State Senate","Do I have to live in my district to run in RI?"]', 'A candidate for the State Senate or House of Representatives in Rhode Island must be a qualified elector (registered voter) and a resident of the district they seek to represent for at least 30 days prior to the election.', 'https://elections.ri.gov/', 'Rhode Island Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('3e67565d2a7a4319', 'RI', '["federal"]', 'candidate_eligibility', 'What are the eligibility requirements for U.S. House and Senate candidates in Rhode Island?', '["US Senate residency requirements Rhode Island","Age to run for Congress in Rhode Island","Federal constitutional requirements for RI candidates"]', 'Federal candidates must meet standard U.S. Constitutional requirements: U.S. House members must be at least 25 years old, a U.S. citizen for 7 years, and an inhabitant of the state when elected. U.S. Senators must be at least 30 years old, a U.S. citizen for 9 years, and an inhabitant of the state when elected.', 'https://elections.ri.gov/', 'Rhode Island Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('ead068a41ab8c777', 'RI', '["state"]', 'candidate_eligibility', 'What are the term limits for the Rhode Island Governor?', '["How many terms can a Rhode Island Governor serve?","Dan McKee term limits RI","Rhode Island executive term limit law"]', 'Under Article IV, Section 1 of the Rhode Island Constitution, the Governor and all other general statewide officers are limited to serving two consecutive four-year terms in office.', 'https://www.rilegislature.gov/riconstitution/Constitution/C04.aspx', 'Rhode Island Constitution Article IV', '2026-05-17', 'static', 'statute_citation', 'Gubernatorial candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('f70a8b6cc7221839', 'RI', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for Attorney General in Rhode Island?', '["Qualifications to run for Attorney General in RI","Do I need to be a member of the bar to be RI AG?","Legal requirements for Rhode Island Attorney General"]', 'The Attorney General is an elected statewide constitutional officer. Under the Rhode Island Constitution, a candidate must be a qualified elector (registered voter) of the state. (Note: Statutory practice and the nature of the role practically necessitate the individual be an attorney admitted to the bar).', 'https://elections.ri.gov/', 'Rhode Island Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('0cbf9aa834827012', 'RI', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for Lieutenant Governor in Rhode Island?', '["Rhode Island Lt Gov requirements","Does the Lt Gov have the same requirements as the Governor in RI?","Qualifications for Lieutenant Governor of Rhode Island"]', 'The qualifications for Lieutenant Governor in Rhode Island are identical to those for Governor. A candidate must be a qualified elector of the state and a resident for at least 30 days prior to the election.', 'https://elections.ri.gov/', 'Rhode Island Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'Statewide executive candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('1ee560e9fe8d4b8c', 'RI', '["county"]', 'candidate_eligibility', 'What are the eligibility requirements for county officeholders in Rhode Island?', '["Rhode Island county executive qualifications","Can I run for county council in RI?","County residency for RI officials"]', 'In a major structural distinctive, Rhode Island has NO county government. The state''s 5 geographic counties exist solely for statistical and judicial boundaries. All local government is conducted at the municipal level across the state''s 39 cities and towns, meaning there are no county-level elected officials.', 'https://elections.ri.gov/', 'Rhode Island Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'County candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('2d9bf56c38472a5f', 'RI', '["federal","state","county","municipal"]', 'voter_interaction', 'Is a photo ID required to vote in person in Rhode Island?', '["Rhode Island voter ID requirements","Do I need my driver''s license to vote in RI?","Acceptable ID for Rhode Island voting"]', 'Yes. Rhode Island law requires all voters to present a valid photo ID prior to voting at the polls (e.g., RI Driver''s License, U.S. Passport, or state Voter ID Card). It is considered a non-strict photo ID state because any voter unable to present valid identification at the polls must be allowed to cast a provisional ballot, which is later verified against their registration signature.', 'https://elections.ri.gov/voter-registration/voter-id', 'Rhode Island Board of Elections - Voter ID', '2026-05-17', 'static', 'official_source_direct', 'All voters', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('8de1199a2c7a0121', 'RI', '["federal","state","county","municipal"]', 'voter_interaction', 'Is Rhode Island a universal mail ballot state, and is no-excuse absentee voting allowed?', '["Do all voters get a mail ballot in Rhode Island?","Rhode Island vote-by-mail system","Do I need an excuse to vote absentee in RI?"]', 'Rhode Island is not a universal mail ballot state (ballots are not automatically mailed to everyone). However, following the passage of the ''Let RI Vote Act'' in 2022, Rhode Island permanently established NO-EXCUSE mail-in voting. Any registered voter may request a mail ballot without providing a reason.', 'https://vote.sos.ri.gov/', 'Rhode Island Department of State', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('3c228c1d76a063d7', 'RI', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Rhode Island offer early in-person voting?', '["Can I vote early in person in RI?","Rhode Island early voting dates 2026","When does early voting start in Rhode Island?"]', 'Yes. Rhode Island offers 20 days of early in-person voting prior to all statewide primaries and general elections. For the September 9, 2026 primary, the early voting period begins on August 20 and concludes at 4:00 p.m. on September 8.', 'https://elections.ri.gov/elections/upcoming-elections', 'Rhode Island Board of Elections', '2026-05-17', 'per_cycle', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('0505666d759c629b', 'RI', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the voter registration deadline and does Rhode Island offer same-day registration?', '["Last day to register to vote in RI","Rhode Island same day voter registration","Voter registration deadline 2026 Rhode Island"]', 'The deadline to register to vote for a full ballot in Rhode Island is 30 days before the election. Rhode Island DOES NOT offer general same-day voter registration for state and local races. Unregistered individuals who show up on Election Day may only register and vote a limited ballot strictly for the offices of President and Vice President.', 'https://vote.sos.ri.gov/', 'Rhode Island Department of State', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('4305cdcfe0531c58', 'RI', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the electioneering buffer zone distance in Rhode Island?', '["How close can I campaign to a polling place in RI?","Rhode Island 50 feet electioneering rule","RI buffer zone around voting centers"]', 'Under Rhode Island law, electioneering is strictly prohibited within the polling place and within 50 feet of the entrance to the building where voting is taking place. This applies to both Election Day and during the early voting period.', 'https://ballotpedia.org/Election_laws_and_legislation_in_Rhode_Island', 'Rhode Island General Assembly (H7572)', '2026-05-17', 'static', 'secondary_source', 'Campaign workers and Voters', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('e379f0ee91c6b249', 'RI', '["federal","state","county","municipal"]', 'voter_interaction', 'How are voting rights restored for individuals with felony convictions in Rhode Island?', '["Can felons vote in Rhode Island state?","Felony voting rights restoration RI","Voting on parole in Rhode Island"]', 'Following a 2006 constitutional amendment, voting rights in Rhode Island are automatically restored to individuals with felony convictions immediately upon their release from incarceration. Individuals who are on probation or parole are fully eligible to register and vote.', 'https://vote.sos.ri.gov/', 'Rhode Island Department of State', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('1eb4cadf64ec1dab', 'RI', '["county"]', 'voter_interaction', 'How is election administration structured across Rhode Island jurisdictions?', '["Rhode Island county election administration","How many local boards of election in RI?","Local election control Rhode Island municipalities"]', 'Because Rhode Island has no county government, elections are administered entirely by local, bipartisan Boards of Canvassers located in each of the state''s 39 cities and towns, functioning under the oversight of the state Board of Elections and Department of State.', 'https://elections.ri.gov/', 'Rhode Island Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'Campaign Strategists', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('32d5e8a73fbd7f18', 'RI', '["federal","state","county","municipal"]', 'voter_interaction', 'How can campaigns access the Rhode Island voter file?', '["Rhode Island voter database access cost","How to get the voter list in RI","What data is included in the Rhode Island voter file?"]', 'Campaigns and political committees can purchase the Central Voter Registry (CVR) list from the Department of State. The file includes voter names, addresses, party affiliations, and participation history, and its use is restricted to political or governmental purposes.', 'https://vote.sos.ri.gov/', 'Rhode Island Department of State', '2026-05-17', 'static', 'official_source_direct', 'Campaign Strategists', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('306c942e3b6e9128', 'RI', '["state","county","municipal"]', 'finance_ethics', 'Which agency administers campaign finance tracking in Rhode Island?', '["Where do I file campaign finance reports in RI?","What is the Rhode Island Board of Elections?","Does the RI Secretary of State handle campaign finance?"]', 'Campaign finance and disclosure laws in Rhode Island are administered and enforced exclusively by the Rhode Island Board of Elections via its Electronic Reporting & Tracking System (ERTS), which is separate from the Department of State.', 'https://elections.ri.gov/campaign-finance', 'Rhode Island Board of Elections - Campaign Finance', '2026-05-17', 'static', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('4d34794972e25fee', 'RI', '["state","county"]', 'finance_ethics', 'What are the individual campaign contribution limits in Rhode Island for the 2026 cycle?', '["Are there contribution limits in Rhode Island?","RI individual donation caps 2026 election","Maximum donation to state legislature Rhode Island"]', 'Rhode Island imposes a flat $1,000 contribution limit per calendar year. An individual may contribute up to $1,000 per year to any candidate for statewide or state legislative office. PACs are also subject to this same $1,000 per candidate, per year limit.', 'https://ballotpedia.org/Campaign_finance_requirements_in_Rhode_Island', 'Ballotpedia / Rhode Island Board of Elections', '2026-05-17', 'static', 'secondary_source', 'Candidates and Donors', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('7fa19540769cc508', 'RI', '["state","county","municipal"]', 'finance_ethics', 'Are corporate contributions permitted in Rhode Island campaigns?', '["Corporate contribution ban Rhode Island state","Can a business donate to my campaign in RI?","Corporate campaign finance rules Rhode Island"]', 'No. Under Rhode Island law, direct contributions from the general treasury of a corporation or labor union to a candidate''s campaign committee or a political party committee are strictly PROHIBITED.', 'https://ballotpedia.org/Campaign_finance_requirements_in_Rhode_Island', 'Ballotpedia / Rhode Island Board of Elections', '2026-05-17', 'static', 'secondary_source', 'Candidates and Businesses', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('b1bdfb71b50652ca', 'RI', '["state","county","municipal"]', 'finance_ethics', 'What is the general campaign finance reporting schedule for Rhode Island candidates?', '["RI BOE filing dates 2026","When are campaign finance reports due in RI?","Rhode Island pre-primary and pre-general report deadlines"]', 'Candidates use the ERTS system to file quarterly reports. During an election year, candidates must also file a 28-day pre-election report, a 7-day pre-election report, and a 28-day post-election report for both the primary and general elections.', 'https://elections.ri.gov/campaign-finance', 'Rhode Island Board of Elections', '2026-05-17', 'per_cycle', 'official_source_direct', 'All candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('6e876c989973f221', 'RI', '["state","county","municipal"]', 'finance_ethics', 'What are Rhode Island''s rapid disclosure requirements for late contributions?', '["Rhode Island 24-hour large contribution report","Late contribution reporting Rhode Island BOE","When do I file a rapid report in RI?"]', 'Rhode Island requires a ''Notice of Receipt of Late Contribution.'' If a candidate receives a contribution of $250 or more in the period between the final pre-election report (7 days prior) and the date of the election, it must be reported to the Board of Elections within 24 hours.', 'https://elections.ri.gov/campaign-finance', 'Rhode Island Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('3e144f558e1bd8ed', 'RI', '["state"]', 'finance_ethics', 'Does Rhode Island provide public financing for state campaigns?', '["Public matching funds for Rhode Island Governor","State funded campaigns Rhode Island status","Government campaign grants RI"]', 'Yes. Rhode Island operates a matching funds program for candidates running for general statewide offices (Governor, Lt. Governor, Attorney General, Secretary of State, General Treasurer). Qualifying candidates who agree to expenditure limits receive two-for-one public matching funds for the first $500 of private contributions from individuals.', 'https://elections.ri.gov/campaign-finance/public-funding', 'Rhode Island Board of Elections - Public Funding', '2026-05-17', 'static', 'official_source_direct', 'State candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('96ac31b0e02897b7', 'RI', '["state","county","municipal"]', 'finance_ethics', 'Are candidates prohibited from using campaign funds for personal use in Rhode Island?', '["RI personal use prohibition campaign finance","Can I use campaign money for personal items in RI?","Prohibited expenditures Rhode Island BOE"]', 'Yes. Rhode Island strictly prohibits the conversion of campaign funds to personal use. Expenditures must be used to defray the ordinary and necessary expenses incurred in connection with the candidate''s campaign or the execution of their public office.', 'https://elections.ri.gov/campaign-finance', 'Rhode Island Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('fb044984e8e349d1', 'RI', '["state"]', 'finance_ethics', 'Is there a session freeze on campaign contributions for Rhode Island legislators?', '["Can Rhode Island legislators raise money during session?","Lobbyist contribution ban RI legislature","Legislative session contribution rules Rhode Island"]', 'Yes. Under Rhode Island law, state officials, legislators, and their campaign committees are explicitly prohibited from holding political fundraising events or accepting campaign contributions from political action committees (PACs) and registered lobbyists during the regular legislative session (which runs from January through its adjournment, typically in June).', 'https://risos-apa-production-public.s3.amazonaws.com/ETHICS/13338/PBC_13338_20250923100346162.pdf', 'Rhode Island Ethics Commission / Board of Elections', '2026-05-17', 'static', 'secondary_source', 'State legislative candidates and Lobbyists', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('2721084ad3a02867', 'RI', '["federal","state"]', 'redistricting', 'Who draws Rhode Island''s congressional and state legislative maps?', '["Does the RI legislature draw district maps?","Who has the authority to draw district lines in Rhode Island?","Rhode Island redistricting commission"]', 'In Rhode Island, the state legislature (General Assembly) holds the ultimate authority to draw and enact both congressional and state legislative district boundaries. However, an 18-member advisory Reapportionment Commission actively assists in drafting and recommending the maps to the legislature.', 'https://ballotpedia.org/Redistricting_in_Rhode_Island', 'Ballotpedia - Redistricting in Rhode Island', '2026-05-17', 'static', 'secondary_source', 'Federal and State candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('042a184399c99fc7', 'RI', '["federal","state"]', 'redistricting', 'What are the legal criteria for redistricting in Rhode Island?', '["Standards for drawing Rhode Island district lines","Rhode Island gerrymandering rules","Map requirements RI"]', 'Under the Rhode Island Constitution and state guidelines, state legislative and congressional districts must be contiguous, be as compact as possible, and be as nearly equal in population as practicable. They must also comply with the federal Voting Rights Act.', 'https://ballotpedia.org/Redistricting_in_Rhode_Island', 'Rhode Island Constitution', '2026-05-17', 'static', 'statute_citation', 'Federal and State candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('7c535558ae1f355f', 'RI', '["state"]', 'redistricting', 'Are the current Rhode Island state legislative maps operative for the 2026 cycle?', '["Status of Rhode Island Senate redistricting maps","Are there pending redistricting lawsuits in Rhode Island?","Rhode Island 2026 state legislative boundaries"]', 'Yes. The redistricting maps enacted by the Rhode Island General Assembly in February 2022 (following the 2020 census) remain fully operative for the 2026 election cycle. There are no ongoing systemic legal challenges preventing their use.', 'https://ballotpedia.org/Redistricting_in_Rhode_Island_after_the_2020_census', 'Ballotpedia - Redistricting in Rhode Island', '2026-05-17', 'static', 'secondary_source', 'State legislative candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('864211299be5b845', 'RI', '["federal"]', 'redistricting', 'What is the status of Rhode Island''s congressional map for the 2026 cycle?', '["Is the RI congressional map operative for 2026?","VRA challenges to Rhode Island congressional districts","Rhode Island congressional redistricting controversy"]', 'The congressional map enacted by the legislature in 2022 remains fully operative for the 2026 election cycle. Rhode Island retained its 2 U.S. House seats, and the new map made minimal boundary changes compared to the prior decade, avoiding significant legal controversy.', 'https://ballotpedia.org/Redistricting_in_Rhode_Island_after_the_2020_census', 'Ballotpedia - Redistricting in Rhode Island', '2026-05-17', 'static', 'secondary_source', 'Federal candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('253fe4dba077af29', 'RI', '["state"]', 'recall_rules', 'Does Rhode Island have a recall mechanism for state officials?', '["Can the Governor of Rhode Island be recalled?","How to recall a state senator in RI","Statewide recall election rules Rhode Island"]', 'Yes, but strictly for ''cause.'' Under Article IV, Section 1 of the Rhode Island Constitution, general state officers (like the Governor or Attorney General) can be recalled ONLY if they have been indicted or convicted of a felony/misdemeanor, or if the ethics commission finds probable cause of a code of ethics violation.', 'https://www.rilegislature.gov/riconstitution/Constitution/C04.aspx', 'Rhode Island Constitution Article IV', '2026-05-17', 'static', 'statute_citation', 'Statewide executive candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('194cab1197a3cfa7', 'RI', '["county","municipal"]', 'recall_rules', 'What are the rules for local recall in Rhode Island?', '["Rhode Island town council recall rules","Signature requirement local recall Rhode Island","Recalling a mayor in RI"]', 'There is no broad statewide statutory right to recall all local officials in Rhode Island. The ability to recall municipal officials (such as a mayor or town council member) is strictly governed by the specific provisions outlined in each individual town or city charter.', 'https://elections.ri.gov/', 'Rhode Island Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'Local candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('2b920dabae69105d', 'RI', '["state"]', 'ballot_access', 'Does Rhode Island have a citizen initiative process?', '["How to get an initiative on the RI ballot","Rhode Island citizen initiative signature requirements","Can citizens propose laws in Rhode Island?"]', 'No. Rhode Island is one of the states that does NOT have a statewide citizen initiative process. Citizens cannot draft statutes or constitutional amendments and gather signatures to place them on the ballot. All statewide ballot measures must be referred by the legislature.', 'https://vote.sos.ri.gov/', 'Rhode Island Department of State', '2026-05-17', 'static', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('45514eb4b9a3b0a0', 'RI', '["state"]', 'ballot_access', 'How does the Rhode Island legislature refer a constitutional amendment to the voters?', '["Legislative referral process Rhode Island","Referendum by legislature RI","Can the RI legislature put a constitutional amendment on the ballot?"]', 'The Rhode Island General Assembly can refer a constitutional amendment to the ballot by securing a simple majority vote (more than 50% of the members elected) in both the State Senate and the House of Representatives. It is then referred directly to the voters on the general election ballot.', 'https://www.rilegislature.gov/riconstitution/Constitution/C14.aspx', 'Rhode Island Constitution Article XIV', '2026-05-17', 'static', 'statute_citation', 'Legislators and Strategists', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('8c0ead6438797e58', 'RI', '["state"]', 'ballot_access', 'Does Rhode Island have a veto referendum process?', '["How to refer a RI bill to the ballot","Rhode Island citizen referendum rules","Veto referendum signature threshold Rhode Island state"]', 'No. Rhode Island does not have a statewide veto referendum process. Citizens cannot gather signatures to suspend and refer an already-passed legislative act to the ballot for a popular vote of approval or rejection.', 'https://vote.sos.ri.gov/', 'Rhode Island Department of State', '2026-05-17', 'static', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('e4cffc6c56a03cac', 'RI', '["state"]', 'ballot_access', 'What voter approval threshold is required to pass ballot measures in Rhode Island?', '["Rhode Island ballot measure pass threshold","Does a measure need a supermajority in RI?","Majority vote requirements Rhode Island ballot measures"]', 'In Rhode Island, a legislatively referred constitutional amendment requires only a simple majority (over 50%) of the total votes cast on that specific measure to pass and become part of the state constitution.', 'https://www.rilegislature.gov/riconstitution/Constitution/C14.aspx', 'Rhode Island Constitution Article XIV', '2026-05-17', 'static', 'statute_citation', 'Ballot measure committees', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('5bd4233122f62e7b', 'RI', '["state"]', 'candidate_eligibility', 'What are the eligibility requirements to run for Secretary of State in Rhode Island?', '["Requirements to run for RI Secretary of State","Who can run for Secretary of State in RI?","Residency rules for Rhode Island SOS"]', 'Under Article IX of the Rhode Island Constitution, a candidate for Secretary of State must be a qualified elector (registered voter) of the state and must have been a resident of Rhode Island for at least 30 days immediately prior to the election.', 'https://elections.ri.gov/', 'Rhode Island Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('6db6f026ae5de337', 'RI', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for General Treasurer in Rhode Island?', '["Eligibility for Rhode Island State Treasurer","Who can run for General Treasurer in RI?","Rhode Island Treasurer residency requirements"]', 'Under Article IX of the Rhode Island Constitution, the qualifications for General Treasurer are identical to those for the Governor. A candidate must be a qualified elector (registered voter) of the state and a resident for at least 30 days immediately prior to the election.', 'https://elections.ri.gov/', 'Rhode Island Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1')
INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('1f7f13e9ec8eb79b', 'RI', '["municipal"]', 'candidate_eligibility', 'What are the eligibility requirements for a school board candidate in Rhode Island?', '["Run for school committee Rhode Island requirements","Who can be a school board member in RI?","School committee residency rules Rhode Island"]', 'To run for a local School Committee in Rhode Island, a candidate must be a qualified elector (registered voter) of the specific municipality or regional school district they seek to represent. Specific charter requirements may apply regarding the length of residency in the specific town.', 'https://elections.ri.gov/', 'Rhode Island Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'School board candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('3baa5790745c9bbd', 'RI', '["judicial"]', 'candidate_eligibility', 'What are the qualifications for Rhode Island Supreme Court justices?', '["Rhode Island Supreme Court Justice eligibility","Years of practice required for RI Supreme Court","Are Rhode Island judges elected or appointed?"]', 'Rhode Island Supreme Court justices are appointed, not elected. While the state constitution does not explicitly list age or residency requirements, statutory law requires nominees to be qualified electors and attorneys admitted to practice law in Rhode Island.', 'https://www.courts.ri.gov/Courts/SupremeCourt/Pages/default.aspx', 'Rhode Island Judiciary', '2026-05-17', 'static', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('33037fa92facaf27', 'RI', '["municipal"]', 'candidate_eligibility', 'What are the eligibility requirements to run for City or Town Council in Rhode Island?', '["Rhode Island city council qualifications","Can I run for town council in RI?","Municipal residency for RI officials"]', 'Because Rhode Island has no county government, local governance is handled entirely by cities and towns. To run for a City or Town Council, a candidate must generally be a qualified elector (registered voter) and a resident of the specific municipality (and ward/district, if applicable) as defined by the local municipal charter.', 'https://elections.ri.gov/', 'Rhode Island Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'Local candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('f8ce12ec88464f6a', 'RI', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the ballot signature cure process for absentee mail-in ballots in Rhode Island?', '["How to fix a rejected signature in RI","Rhode Island ballot cure process deadline","Missing signature on RI mail ballot"]', 'Rhode Island provides a formal ballot cure process. The local board of canvassers is responsible for notifying voters by mail, email, or phone if there is a missing or mismatched signature on their mail-in ballot return envelope. Voters have until seven days after Election Day to correct the deficiency so their ballot can be counted.', 'https://vote.sos.ri.gov/', 'Rhode Island Department of State', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('f9302d80fc0696cc', 'RI', '["federal","state","county","municipal"]', 'voter_interaction', 'What are the deadlines for military and overseas (UOCAVA) voters in Rhode Island?', '["When are military ballots due in Rhode Island?","UOCAVA return deadline RI","Overseas voting rules Rhode Island state"]', 'Under UOCAVA, ballots are transmitted to military and overseas voters at least 45 days before an election. Voted ballots returned by mail or via the state''s secure electronic portal must be received by the Board of Elections no later than the close of polls (8:00 p.m.) on Election Day.', 'https://vote.sos.ri.gov/Voter/MilitaryAndOverseas', 'Rhode Island Department of State - UOCAVA', '2026-05-17', 'static', 'official_source_direct', 'UOCAVA voters', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('04c9deca83ca448e', 'RI', '["federal","state","county","municipal"]', 'voter_interaction', 'When are provisional ballots used in Rhode Island?', '["What is a provisional ballot in RI?","Voting without ID Rhode Island","When do election workers issue provisional ballots?"]', 'Provisional ballots are issued if a voter fails to present an acceptable photo ID at the polls, or if their name is not listed on the official poll book but they affirm they are registered. The provisional ballot is sealed and evaluated post-election; if the voter''s signature matches their registration record, the ballot is counted without the voter needing to return with an ID.', 'https://elections.ri.gov/voter-registration/voter-id', 'Rhode Island Board of Elections - Voter ID', '2026-05-17', 'static', 'official_source_direct', 'Voters and Poll Watchers', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('a8ac786884b33f51', 'RI', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Rhode Island have Automatic Voter Registration (AVR) at the DMV?', '["Is registration automatic at the Rhode Island DMV?","RI motor voter automatic registration","Do I have to register to vote if I get a RI driver''s license?"]', 'Yes. Rhode Island implemented Automatic Voter Registration (AVR) following legislation enacted in 2017. Eligible individuals interacting with the Division of Motor Vehicles are automatically registered to vote or have their address updated, unless they actively decline (opt-out) during the transaction.', 'https://vote.sos.ri.gov/', 'Rhode Island Department of State', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('d16d7d1f88651070', 'RI', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Rhode Island offer Online Voter Registration?', '["Can I register to vote online in RI?","Rhode Island electronic voter registration","RI online registration portal"]', 'Yes. Eligible Rhode Island residents with a valid state driver''s license or state ID card can register to vote or update their registration securely using the Department of State''s online voter registration portal. The deadline is 30 days prior to the election.', 'https://vote.sos.ri.gov/Home/RegistertoVote', 'Rhode Island Department of State - OVR', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('240b58312e3e24bb', 'RI', '["federal","state","county","municipal"]', 'voter_interaction', 'How does Rhode Island maintain its voter registration lists?', '["RI voter list maintenance rules","How are inactive voters handled in Rhode Island?","Rhode Island voter roll cleaning process"]', 'Rhode Island conducts list maintenance using the Electronic Registration Information Center (ERIC) and National Change of Address (NCOA) data. Voters whose mail is returned undeliverable are sent a confirmation notice. If they fail to respond and do not vote in two consecutive federal general elections, their registration is removed from the active rolls.', 'https://vote.sos.ri.gov/', 'Rhode Island Department of State', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('8f72896624d73412', 'RI', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the deadline to return an absentee ballot in Rhode Island?', '["When is the last day to mail my ballot in RI?","Rhode Island mail ballot postmark deadline","What time are ballots due in Rhode Island?"]', 'Rhode Island strictly requires that all voted absentee mail ballots be received by the State Board of Elections by 8:00 p.m. on Election Day. A postmark is not sufficient; ballots physically arriving after the 8:00 p.m. deadline are rejected. Voters may also use secure drop boxes placed throughout the state up until 8:00 p.m.', 'https://vote.sos.ri.gov/', 'Rhode Island Department of State - Mail Ballots', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('b6cd366affe57261', 'RI', '["state","county","municipal"]', 'runoff_rules', 'Is Ranked Choice Voting (RCV) used in Rhode Island?', '["Does Rhode Island use ranked choice voting?","RCV status in Rhode Island 2026","Instant runoff voting RI"]', 'No. Ranked Choice Voting (RCV) is not used for any state, federal, or widespread municipal elections in Rhode Island. Elections are decided strictly by a traditional plurality voting system.', 'https://elections.ri.gov/', 'Rhode Island Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('e354acace2649850', 'RI', '["federal","state","county"]', 'runoff_rules', 'How are exact ties broken in Rhode Island elections?', '["How are tied elections decided in Rhode Island?","Tie-breaker rules Rhode Island elections","What happens if a race is tied in RI?"]', 'In Rhode Island, if a general election for a statewide ''general officer'' results in an exact tie, the General Assembly elects one of the tied candidates by a joint vote at the start of its next session. For a tie in a state legislative race, a new special election is ordered to resolve the tie.', 'https://www.cga.ct.gov/2006/rpt/2006-R-0764.htm', 'Rhode Island Statutes / General Assembly Review', '2026-05-17', 'static', 'secondary_source', 'All candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('9cbc5648cf9b3a8c', 'RI', '["state","county","municipal"]', 'finance_ethics', 'What disclaimer language is required on Rhode Island campaign materials?', '["Rhode Island ''Paid for by'' rules","Campaign ad disclaimer requirements RI","Political taglines Rhode Island BOE"]', 'Rhode Island campaign finance law requires that all political advertising and campaign materials clearly identify the entity financing the communication. The disclaimer must state ''Paid for by'' followed by the name of the candidate committee, PAC, or individual who authorized and paid for the message.', 'https://elections.ri.gov/campaign-finance', 'Rhode Island Board of Elections - Campaign Finance', '2026-05-17', 'static', 'official_source_direct', 'All candidates and PACs', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('5fe13efce006ac79', 'RI', '["state","county","municipal"]', 'finance_ethics', 'When does outside spending become prohibited coordination in Rhode Island?', '["RI campaign coordination rules","When is a PAC expenditure not independent in Rhode Island?","Prohibition on candidate-PAC coordination RI"]', 'An independent expenditure becomes ''coordinated'' if it is made in cooperation, consultation, or concert with, or at the request or suggestion of, a candidate or their committee. Once coordinated, the expenditure is treated as an in-kind contribution and is subject to the strict $1,000 per calendar year contribution limit.', 'https://elections.ri.gov/campaign-finance', 'Rhode Island Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'All candidates and IECs', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('015e525770c9bdec', 'RI', '["state","county","municipal"]', 'finance_ethics', 'What are the penalties for late campaign finance filings in Rhode Island?', '["RI BOE late fee","Penalty for missing a Rhode Island campaign finance deadline","Board of Elections fine for late filing RI"]', 'The Rhode Island Board of Elections automatically assesses administrative penalties for late campaign finance reports. Under the ERTS system, committees are typically fined $25 for reports filed late, but fines can escalate up to statutory maximums if the report remains unfiled after formal notices.', 'https://elections.ri.gov/campaign-finance', 'Rhode Island Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('59e714329a4f4afe', 'RI', '["state","county","municipal"]', 'finance_ethics', 'When and how must a Rhode Island campaign committee terminate?', '["Closing a Rhode Island campaign committee","ERTS committee termination requirements","Final campaign finance report Rhode Island"]', 'A candidate committee may formally terminate when it has achieved a zero cash balance, legally disposed of all unexpended funds, and resolved all outstanding debts or loans. A formal Notice of Dissolution must be filed via the ERTS portal with the Board of Elections.', 'https://elections.ri.gov/campaign-finance', 'Rhode Island Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('e72b249dfa8b6dc5', 'RI', '["state","county","municipal"]', 'finance_ethics', 'What are the disclosure rules for independent expenditures in Rhode Island?', '["RI independent expenditure reporting BOE","Disclosure for RI independent expenditure groups","Reporting thresholds for outside spending Rhode Island"]', 'Any person, PAC, or organization that spends more than $1,000 on independent expenditures in a calendar year to advocate for or against a candidate must file an independent expenditure report with the Board of Elections detailing the spending and identifying major donors.', 'https://elections.ri.gov/campaign-finance', 'Rhode Island Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'Independent groups and PACs', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('edd5ff9a6fcdc8fe', 'RI', '["state","county","municipal"]', 'finance_ethics', 'How are in-kind contributions valued and reported in Rhode Island?', '["Rhode Island in-kind contribution valuation rules","Reporting non-monetary donations Rhode Island campaign","Fair market value for in-kind gifts RI"]', 'In-kind contributions (donated goods, services, or equipment not available to the general public) must be reported on ERTS disclosures at their fair market value. They count directly toward the donor''s $1,000 per calendar year contribution limit.', 'https://elections.ri.gov/campaign-finance', 'Rhode Island Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('4fcdc08a817ef6d4', 'RI', '["state","county","municipal"]', 'finance_ethics', 'Are there limits on a candidate loaning personal funds to their own campaign in Rhode Island?', '["Rhode Island candidate personal loan limits","Can I pay myself back for a campaign loan in RI?","Reporting candidate loans in ERTS"]', 'A candidate may loan or contribute an UNLIMITED amount of their own personal funds to their campaign committee; these funds are exempt from standard contribution limits (except for candidates voluntarily accepting public matching funds). Loans must be properly documented on disclosures and may be repaid from campaign contributions.', 'https://elections.ri.gov/campaign-finance', 'Rhode Island Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('246f9ca9f117d8e2', 'RI', '["state","county","municipal"]', 'finance_ethics', 'What can Rhode Island candidates do with unexpended campaign funds?', '["What can I do with leftover campaign money in RI?","RI surplus campaign funds rules","Donating remaining campaign funds Rhode Island"]', 'Unexpended campaign funds cannot be converted to personal use. Candidates may retain surplus funds for a future campaign, return them pro-rata to contributors, transfer them to a recognized political party, or donate them to an IRS-recognized tax-exempt charitable organization.', 'https://elections.ri.gov/campaign-finance', 'Rhode Island Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('3e523d2efb72b2e4', 'RI', '["state","county"]', 'finance_ethics', 'What are the PAC contribution limits to candidates in Rhode Island?', '["RI PAC donation limits to candidates 2026","Political committee vs individual contribution limit Rhode Island","Maximum PAC gift to state legislator RI"]', 'In Rhode Island, Political Action Committees (PACs) are subject to the EXACT SAME strict contribution limits as individuals. A PAC is capped at donating a maximum of $1,000 per calendar year to any candidate for statewide or legislative office.', 'https://ballotpedia.org/Campaign_finance_requirements_in_Rhode_Island', 'Ballotpedia / Rhode Island Board of Elections', '2026-05-17', 'static', 'secondary_source', 'State and County candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('1d03a74575340153', 'RI', '["municipal"]', 'election_dates', 'When are municipal elections held in Rhode Island?', '["Rhode Island local election dates","When are mayors elected in RI?","Town council election cycle Rhode Island"]', 'The vast majority of Rhode Island''s 39 cities and towns hold their municipal elections (for mayors, town councils, and school committees) in November of even-numbered years, meaning they are held concurrently with state and federal general elections.', 'https://vote.sos.ri.gov/', 'Rhode Island Department of State', '2026-05-17', 'static', 'official_source_direct', 'Local candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('9cee97dfcdc2be00', 'RI', '["state","county","municipal"]', 'election_dates', 'What is the canvassing and certification timeline for Rhode Island elections?', '["When are Rhode Island election results official?","RI certification deadline","Board of Elections meeting Rhode Island"]', 'Local boards of canvassers compile returns immediately following Election Day. The State Board of Elections then conducts a final tabulation and officially certifies the statewide and federal election returns, which usually takes two to three weeks depending on provisional ballot curing.', 'https://elections.ri.gov/', 'Rhode Island Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'All candidates and campaigns', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('6f1046223ee35cda', 'RI', '["federal","state"]', 'election_dates', 'When and how are special elections called in Rhode Island?', '["Rhode Island special election timeline","Who calls a special election to fill a US House vacancy in RI?","Filling a midterm vacancy Rhode Island"]', 'Special elections to fill federal or state legislative vacancies are generally called by the Governor. The Governor sets the exact dates for the special primary and general election to ensure adequate time for candidate filing, ballot printing, and UOCAVA compliance.', 'https://vote.sos.ri.gov/', 'Rhode Island Department of State', '2026-05-17', 'static', 'official_source_direct', 'Federal and State candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1'),
  ('142a245f4f9717d8', 'RI', '["state"]', 'election_dates', 'Who sits on the Rhode Island Board of Elections?', '["Who certifies statewide elections in RI?","Rhode Island Board of Elections composition","Who oversees the local boards of canvassers in RI?"]', 'The Rhode Island Board of Elections is an independent regulatory agency comprised of seven members. The commissioners are appointed by the Governor, with the advice and consent of the State Senate, and they serve staggered nine-year terms.', 'https://elections.ri.gov/about-us', 'Rhode Island Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T22-56-35_rhode_island_full_v1')
